1152	[Čech acyclicity for the structure sheaf]
1153	  \label{thm:basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
1154	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
1155	  \uses{def:Scheme_basicOpenCover, def:Scheme_IsCechAcyclicCover, thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod, thm:Scheme_basicOpenCover_finset_inf_le, thm:Scheme_basicOpenCover_finset_inf_isLocalization, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
